#!/usr/bin/env node
/**
 * Splices the SVGs generated by generate-about-monograms.ts into about.html
 * at `<!-- SVG:KEY -->` placeholders. One-off tooling, not part of the app
 * build — about.html ships with the real markup already inlined.
 *
 * Usage: node scripts/generate-about-monograms.ts && node scripts/inject-about-monograms.mjs
 */
import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const jsonPath = path.join(__dirname, "../.tmp-about-monograms.json");
const htmlPath = path.join(__dirname, "../about.html");

const monograms = JSON.parse(await fs.readFile(jsonPath, "utf8"));
let html = await fs.readFile(htmlPath, "utf8");

for (const [key, svg] of Object.entries(monograms)) {
  const placeholder = `<!-- SVG:${key} -->`;
  if (!html.includes(placeholder)) {
    console.error(`Placeholder ${placeholder} not found in about.html`);
    process.exitCode = 1;
    continue;
  }
  html = html.replace(placeholder, svg);
}

await fs.writeFile(htmlPath, html);
await fs.unlink(jsonPath);
console.log(
  `Injected ${Object.keys(monograms).length} monograms into about.html`,
);
